const response = JSON.parse($input.first().json.data).response;
// Extract JSON from response
const match = response.match(/\{[\s\S]*\}/);
if (match) {
  const content = JSON.parse(match[0]);
  return [{ json: { ...content, topic: $('Content Parameters').first().json.topic, generated_at: new Date().toISOString() } }];
}
throw new Error('Failed to parse AI response as JSON');

const response = JSON.parse($input.first().json.data).response;
const match = response.match(/\{[\s\S]*\}/);
const original = $('Parse Content JSON').first().json;
if (match) {
  try {
    const reviewed = JSON.parse(match[0]);
    return [{ json: { ...original, ...reviewed, reviewed: true } }];
  } catch(e) {}
}
return [{ json: { ...original, reviewed: false } }];
